// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading) {
		return;
	} else if(newValue === ''){
		// STRY0156233 
		if(!g_form.isNewRecord()){
			displayDefaultReviewerMessage();
		}
		// if the newValue is cleared, then update messages, but don't do the rest.
		updateOOOMsg();
		return;
	}
	if(oldValue != newValue) {
		g_form.setValue("reviewer_manual_update", true);
		g_form.setDisplay("reviewer_manual_update", false);
		g_form.setReadOnly("reviewer_manual_update", false);
	}

	// STRY0156233 
	function displayDefaultReviewerMessage(){
		var msg = getMessage("Tasker - If the Reviewer field is empty, the Reviewer will be [{0}].");
		msg = msg.replace("{0}", g_scratchpad.reviewerDisplayValue);
		g_form.showFieldMsg("u_reviewer", msg);
	}

	// STRY0130635 - onchange reset the OOO to the new user
	updateOOOMsg();
	function updateOOOMsg (){
		// STRY0130635 - init was done in onload function
		var dt_ooo = x_153465_discovert.DTech_Out_of_Office;
		dt_ooo.ooo_change_user("u_reviewer");

	}	

}
